import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Avançado: Pipeline e Mecanismos Internos | Tutorial AI App Factory","description":"Aprofunde-se no pipeline de 7 fases do AI App Factory, no escalonador Sisyphus, mecanismos de permissão e segurança, e estratégias de tratamento de falhas. Domine técnicas de otimização de contexto e configurações avançadas.","frontmatter":{"title":"Avançado: Pipeline e Mecanismos Internos | Tutorial AI App Factory","sidebarTitle":"Avançado: Pipeline","subtitle":"Avançado: Pipeline e Mecanismos Internos","description":"Aprofunde-se no pipeline de 7 fases do AI App Factory, no escalonador Sisyphus, mecanismos de permissão e segurança, e estratégias de tratamento de falhas. Domine técnicas de otimização de contexto e configurações avançadas.","tags":["Pipeline","Escalonador","Permissão e Segurança","Tratamento de Falhas"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"pt/hyz1992/agent-app-factory/advanced/index.md","filePath":"pt/hyz1992/agent-app-factory/advanced/index.md"}'),s={name:"pt/hyz1992/agent-app-factory/advanced/index.md"};function r(n,e,d,l,c,p){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="avancado-pipeline-e-mecanismos-internos" tabindex="-1">Avançado: Pipeline e Mecanismos Internos <a class="header-anchor" href="#avancado-pipeline-e-mecanismos-internos" aria-label="Permalink to &quot;Avançado: Pipeline e Mecanismos Internos&quot;">​</a></h1><p>Este capítulo explica em profundidade os mecanismos centrais e funcionalidades avançadas do AI App Factory, incluindo os princípios operacionais detalhados do pipeline de 7 fases, as estratégias de escalonamento do escalonador Sisyphus, mecanismos de permissão e segurança, estratégias de tratamento de falhas, e como otimizar o contexto para economizar custos de Token.</p><div class="warning custom-block"><p class="custom-block-title">Pré-requisitos</p><p>Antes de estudar este capítulo, certifique-se de ter concluído:</p><ul><li><a href="./../../start/getting-started/">Início Rápido</a> e <a href="./../../start/installation/">Instalação e Configuração</a></li><li><a href="./../../start/pipeline-overview/">Visão Geral do Pipeline de 7 Fases</a></li><li>Configuração de <a href="./../../platforms/claude-code/">Integração de Plataformas</a></li></ul></div><h2 id="conteudo-do-capitulo" tabindex="-1">Conteúdo do Capítulo <a class="header-anchor" href="#conteudo-do-capitulo" aria-label="Permalink to &quot;Conteúdo do Capítulo&quot;">​</a></h2><p>Este capítulo inclui os seguintes tópicos:</p><h3 id="detalhamento-do-pipeline-de-7-fases" tabindex="-1">Detalhamento do Pipeline de 7 Fases <a class="header-anchor" href="#detalhamento-do-pipeline-de-7-fases" aria-label="Permalink to &quot;Detalhamento do Pipeline de 7 Fases&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">Fase 1: Bootstrap - Estruturar Ideia de Produto</a></strong></p><ul><li>Aprenda a transformar ideias vagas de produto em documentos estruturados</li><li>Entenda o formato de entrada e saída do Bootstrap Agent</li></ul></li><li><p><strong><a href="./stage-prd/">Fase 2: PRD - Gerar Documento de Requisitos de Produto</a></strong></p><ul><li>Gere PRD nível MVP, incluindo histórias de usuário, lista de funcionalidades e não-objetivos</li><li>Domine técnicas de decomposição de requisitos e priorização</li></ul></li><li><p><strong><a href="./stage-ui/">Fase 3: UI - Design de Interface e Protótipo</a></strong></p><ul><li>Use a skill ui-ux-pro-max para designar estrutura de UI e protótipos visualizáveis</li><li>Entenda o fluxo de design de interface e melhores práticas</li></ul></li><li><p><strong><a href="./stage-tech/">Fase 4: Tech - Design de Arquitetura Técnica</a></strong></p><ul><li>Design arquitetura técnica mínima viável e modelo de dados Prisma</li><li>Domine princípios de seleção de tecnologia e design de arquitetura</li></ul></li><li><p><strong><a href="./stage-code/">Fase 5: Code - Gerar Código Executável</a></strong></p><ul><li>Gere código frontend e backend, testes e configurações com base no Schema de UI e design Tech</li><li>Entenda o fluxo de geração de código e sistema de templates</li></ul></li><li><p><strong><a href="./stage-validation/">Fase 6: Validation - Validar Qualidade de Código</a></strong></p><ul><li>Valide instalação de dependências, verificação de tipos, schema Prisma e qualidade de código</li><li>Domine fluxos de verificação de qualidade automatizados</li></ul></li><li><p><strong><a href="./stage-preview/">Fase 7: Preview - Gerar Guia de Deploy</a></strong></p><ul><li>Gere documentação completa de instruções de execução e configuração de deploy</li><li>Aprenda integração CI/CD e configuração de Git Hooks</li></ul></li></ul><h3 id="mecanismos-internos" tabindex="-1">Mecanismos Internos <a class="header-anchor" href="#mecanismos-internos" aria-label="Permalink to &quot;Mecanismos Internos&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Detalhamento do Escalonador Sisyphus</a></strong></p><ul><li>Entenda como o escalonador coordena o pipeline, gerencia estado e executa verificações de permissão</li><li>Domine estratégias de escalonamento e princípios de máquina de estado</li></ul></li><li><p><strong><a href="./context-optimization/">Otimização de Contexto: Execução por Sessão</a></strong></p><ul><li>Aprenda a usar o comando <code>factory continue</code> para economizar Tokens</li><li>Domine melhores práticas de criar novas sessões em cada fase</li></ul></li><li><p><strong><a href="./security-permissions/">Mecanismos de Permissão e Segurança</a></strong></p><ul><li>Entenda matriz de limites de capacidade, tratamento de ultrapassagem e mecanismos de verificação de segurança</li><li>Domine configurações de segurança e gerenciamento de permissões</li></ul></li><li><p><strong><a href="./failure-handling/">Tratamento de Falhas e Rollback</a></strong></p><ul><li>Aprenda identificação de falhas, mecanismos de retry, estratégias de rollback e fluxos de intervenção humana</li><li>Domine técnicas de troubleshooting e recuperação</li></ul></li></ul><h2 id="recomendacoes-de-rota-de-aprendizado" tabindex="-1">Recomendações de Rota de Aprendizado <a class="header-anchor" href="#recomendacoes-de-rota-de-aprendizado" aria-label="Permalink to &quot;Recomendações de Rota de Aprendizado&quot;">​</a></h2><h3 id="ordem-recomendada-de-estudo" tabindex="-1">Ordem Recomendada de Estudo <a class="header-anchor" href="#ordem-recomendada-de-estudo" aria-label="Permalink to &quot;Ordem Recomendada de Estudo&quot;">​</a></h3><ol><li><p><strong>Primeiro conclua o Pipeline de 7 Fases</strong> (em ordem)</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>Cada fase tem entradas e saídas claras; aprender em ordem constrói compreensão completa</li></ul></li><li><p><strong>Depois estude o Escalonador e Otimização de Contexto</strong></p><ul><li>Entenda como o Sisyphus coordena as 7 fases</li><li>Aprenda a otimizar contexto para economizar custos de Token</li></ul></li><li><p><strong>Finalmente estude Segurança e Tratamento de Falhas</strong></p><ul><li>Domine limites de permissão e mecanismos de segurança</li><li>Entenda cenários de falha e estratégias de resposta</li></ul></li></ol><h3 id="foco-de-estudo-por-papel" tabindex="-1">Foco de Estudo por Papel <a class="header-anchor" href="#foco-de-estudo-por-papel" aria-label="Permalink to &quot;Foco de Estudo por Papel&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Papel</th><th>Capítulos Focados</th></tr></thead><tbody><tr><td><strong>Desenvolvedor</strong></td><td>Code, Validation, Tech, Orchestrator</td></tr><tr><td><strong>Product Manager</strong></td><td>Bootstrap, PRD, UI, Preview</td></tr><tr><td><strong>Tech Lead</strong></td><td>Tech, Code, Security, Failure Handling</td></tr><tr><td><strong>DevOps Engineer</strong></td><td>Validation, Preview, Context Optimization</td></tr></tbody></table><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode continuar estudando:</p><ul><li><strong><a href="./../../faq/troubleshooting/">Perguntas Frequentes e Troubleshooting</a></strong> - Resolva problemas no uso prático</li><li><strong><a href="./../../faq/best-practices/">Melhores Práticas</a></strong> - Domine técnicas de uso eficiente do Factory</li><li><strong><a href="./../../appendix/cli-commands/">Referência de Comandos CLI</a></strong> - Veja lista completa de comandos</li><li><strong><a href="./../../appendix/code-standards/">Padrões de Código</a></strong> - Entenda padrões de código gerado</li></ul><hr><p>💡 <strong>Dica</strong>: Se encontrar problemas durante o uso, consulte primeiro o capítulo <a href="./../../faq/troubleshooting/">Perguntas Frequentes e Troubleshooting</a>.</p>',19)])])}const g=a(s,[["render",r]]);export{m as __pageData,g as default};
